mapper.select:
SELECT namespace, entity_type, seed_key, entity_id, pack_version, content_hash, metadata
FROM seed_content_identity
WHERE namespace = #{namespace}
  AND entity_type = #{entityType}
  AND seed_key = #{seedKey}
LIMIT 1

mapper.update:
UPDATE seed_content_identity
SET pack_version = #{packVersion},
    content_hash = #{contentHash},
    metadata = #{metadataJson},
    updated_at = NOW(3)
WHERE namespace = #{namespace}
  AND entity_type = #{entityType}
  AND seed_key = #{seedKey}

