mapper.select:
SELECT id
FROM comments
WHERE post_id = #{postId}
  AND user_id = #{authorId}
ORDER BY created_at ASC, id ASC
LIMIT 1 OFFSET #{ordinal}

mapper.update:
UPDATE comments c JOIN seed_content_identity i ON i.entity_id = c.id AND i.namespace = #{namespace} AND i.entity_type = 'COMMENT' SET c.deleted_at = CURRENT_TIMESTAMP, c.updated_at = CURRENT_TIMESTAMP WHERE c.deleted_at IS NULL
AND i.seed_key NOT IN
#{seedKey}

mapper.select:
SELECT f.id AS following_id, r.id AS follower_id
FROM (SELECT 1 AS anchor_row) anchor
LEFT JOIN following f
  ON f.from_user_id = #{fromUserId}
 AND f.to_user_id = #{toUserId}
LEFT JOIN follower r
  ON r.from_user_id = #{fromUserId}
 AND r.to_user_id = #{toUserId}
LIMIT 1

mapper.update:
UPDATE following SET rel_status = 0, updated_at = CURRENT_TIMESTAMP(3) WHERE rel_status = 1
AND from_user_id IN
#{accountId}
AND to_user_id IN
#{accountId}
AND 1 = 0
AND NOT (
(from_user_id = #{pair.fromUserId} AND to_user_id = #{pair.toUserId})
)

UPDATE follower SET rel_status = 0, updated_at = CURRENT_TIMESTAMP(3) WHERE rel_status = 1
AND from_user_id IN
#{accountId}
AND to_user_id IN
#{accountId}
AND 1 = 0
AND NOT (
(from_user_id = #{pair.fromUserId} AND to_user_id = #{pair.toUserId})
)
